<?php
declare(strict_types=1);
require_once dirname(__DIR__,2).'/includes/portal_estudiante_layout.php';
$portal=portalEstudianteCabecera('Mis capacitaciones','cursos','Pagos confirmados, sección asignada y acceso académico.');$pdo=obtenerConexion();
$q=$pdo->prepare("SELECT a.id,a.codigo,a.nombre,a.descripcion,CONCAT_WS(' ',d.nombre,d.apellido) docente,s.codigo seccion,i.estado FROM inscripciones_capacitacion i JOIN asignaturas a ON a.id=i.asignatura_id LEFT JOIN usuarios d ON d.id=i.docente_id LEFT JOIN capacitacion_secciones s ON s.id=i.seccion_id WHERE i.usuario_id=:u AND i.estado IN('pendiente_asignacion','inscrito','finalizado') UNION ALL SELECT a.id,a.codigo,a.nombre,a.descripcion,CONCAT_WS(' ',d.nombre,d.apellido) docente,NULL seccion,ed.estado FROM estudiantes_docentes ed JOIN asignaturas a ON a.id=ed.asignatura_id JOIN usuarios d ON d.id=ed.docente_id WHERE ed.estudiante_id=:u2 AND ed.estado='activo' AND NOT EXISTS(SELECT 1 FROM inscripciones_capacitacion i2 WHERE i2.usuario_id=ed.estudiante_id AND i2.asignatura_id=ed.asignatura_id) ORDER BY nombre");$q->execute(['u'=>$_SESSION['usuario_id'],'u2'=>$_SESSION['usuario_id']]);$cursos=$q->fetchAll();
?><div class="row"><?php foreach($cursos as$c):?><div class="col-md-6"><div class="card h-100"><div class="card-body"><span class="badge bg-primary"><?=atenea_e($c['codigo'])?></span><h2 class="h4 mt-3"><?=atenea_e($c['nombre'])?></h2><p class="text-muted"><?=atenea_e((string)$c['descripcion'])?></p><?php if($c['estado']==='pendiente_asignacion'):?><div class="alert alert-warning">Tu pago está confirmado. La asignación de docente y sección está pendiente; no debes pagar nuevamente.</div><?php else:?><p><i class="bi bi-person-video3"></i> <?=atenea_e($c['docente']?:'Por asignar')?><?php if($c['seccion']):?> · Sección <?=atenea_e($c['seccion'])?><?php endif;?></p><a class="btn btn-primary" href="curso.php?id=<?=$c['id']?>">Abrir curso</a><?php endif;?></div></div></div><?php endforeach;?><?php if(!$cursos):?><div class="col-12"><div class="card"><div class="card-body text-center py-5"><i class="bi bi-journal-bookmark display-3 text-primary"></i><h2 class="h4 mt-3">No hay capacitaciones asignadas</h2><p class="text-muted mb-0">Tu cuenta no tiene pagos académicos confirmados ni matrículas activas.</p></div></div></div><?php endif;?></div><?php portalEstudiantePie();
